import { message, Form, theme, Tooltip } from 'antd';
import React, { useState } from 'react';
import { ModalForm, ProFormText, ProFormSelect, ProFormList, ProFormDigit, ProFormCheckbox } from '@ant-design/pro-form';
import { useIntl, useAntdConfig } from '@umijs/max';
import type { API } from '@/services/typings';
import styles from "./styles.css"
import { updateOidcProviders } from '@/services/api';
import UploadSvgComponent from '@/components/Others/upload_svg';
import { t } from '@/global';

import { getDefaultIcon, shouldShowField, pemfileRules, forceMetadataTimeoutRules } from '..';
import { checkHasAlgorithm } from '@/components/RightContent/ThemeSwitch';
import { getOidcSettings } from '@/global';
const { darkAlgorithm } = theme;

export type NewFormDataType = {
    getCallbackUrl: () => string | undefined;
    getUseAvatar: () => boolean | undefined;
    visible: boolean,
    handleModalVisible: React.Dispatch<React.SetStateAction<boolean>>,
    ops: string[],
    onAdded: (n: string) => void,
};

export const ExtraScopesFormList = (btnText: string, disabled: () => boolean, op?: string) => {
    return <>
        <div style={{ width: op ? 700 : undefined }}>
            <ProFormList
                name={op ? ['providers', op, 'extra_scopes'] : 'extra_scopes'}
                copyIconProps={false}
                deleteIconProps={disabled() ? false : undefined}
                creatorButtonProps={{
                    position: 'top',
                    creatorButtonText: btnText,
                    disabled: disabled(),
                }}
                max={15}
                alwaysShowItemLabel={false}
            >
                <ProFormText
                    name='scope'
                    disabled={disabled()}
                    required
                    placeholder={'scope'}
                    width='md'
                />
            </ProFormList>
        </div>
    </>;
};

export const ExtraParamsFormList = (btnText: string, disabled: () => boolean, op?: string) => {
    return <>
        <div style={{ width: op ? 700 : undefined }}>
            <ProFormList
                name={op ? ['providers', op, 'extra_params'] : 'extra_params'}
                copyIconProps={false}
                deleteIconProps={disabled() ? false : undefined}
                creatorButtonProps={{
                    position: 'top',
                    creatorButtonText: btnText,
                    disabled: disabled(),
                }}
                max={15}
                alwaysShowItemLabel={false}
            >
                <div className={styles['extra-params']}>
                    <ProFormText
                        disabled={disabled()}
                        className={styles['extra-params-key']}
                        name='key'
                        placeholder={'key'}
                    />
                    <div style={{ width: '10px' }} />
                    <ProFormText
                        disabled={disabled()}
                        className={styles['extra-params-value']}
                        name='value'
                        placeholder={'value'}
                    />
                </div>
            </ProFormList>
        </div >
    </>;
}

const NewForm: React.FC<NewFormDataType> = ({ getCallbackUrl, getUseAvatar, visible, handleModalVisible, ops, onAdded }) => {
    const intl = useIntl();
    const [authType, setAuthType] = useState<string | undefined>(undefined);
    const [icon, setIcon] = useState<string | undefined>(undefined);
    const [form] = Form.useForm();
    const antdConfig = useAntdConfig();
    const isDark = checkHasAlgorithm(antdConfig, darkAlgorithm);
    const oidcSettings = getOidcSettings(isDark) as any;

    const knownOps = Object.keys(oidcSettings).filter((key) => key !== 'icon');
    const authTypes = [...knownOps, 'custom'].filter((type) => !ops.includes(type));

    const plain = (text: string, defaultMessage = '') => t(`pages.Settings.OIDC.new.${text}`, true, defaultMessage || text, intl) as string;

    const getNewCustomItems = (op: string | undefined) => {
        return <>
            {
                !shouldShowField(op, 'authorization_endpoint') ? null : <ProFormText
                    name='authorizationEndpoint'
                    label={plain('Authorization Endpoint', '')}
                />
            }
            {
                !shouldShowField(op, 'token_endpoint') ? null : <ProFormText
                    name='tokenEndpoint'
                    label={plain('Token Endpoint', '')}
                />
            }
            {
                !shouldShowField(op, 'userinfo_endpoint') ? null : <ProFormText
                    name='userinfoEndpoint'
                    label={plain('Userinfo Endpoint', '')}
                />
            }
            {
                !shouldShowField(op, 'jwks_endpoint') ? null : <ProFormText
                    name='jwksEndpoint'
                    label={plain('JWKS Endpoint', '')}
                />
            }
            {
                !shouldShowField(op, 'pkce') ? null : <ProFormCheckbox name='pkce' initialValue={false}>
                    {plain('Enable PKCE', '')}
                </ProFormCheckbox>
            }

            {
                !shouldShowField(op, 'map_groups') ? null : <ProFormCheckbox name='mapGroups' initialValue={false}>
                    <Tooltip title={t('pages.Settings.OIDC.oidc_map_groups_tooltip')}>
                        <span>{plain('Map Groups')}</span>
                    </Tooltip>
                </ProFormCheckbox>
            }

            {!shouldShowField(op, 'extra_scopes') ? null : ExtraScopesFormList(plain('Add Extra Scope'), () => false)}
            {!shouldShowField(op, 'extra_params') ? null : ExtraParamsFormList(plain('Add Extra Param'), () => false)}
        </>;
    }

    const nameRules = [
        {
            required: true,
        },
        {
            validator: (_: any, value: string) => {
                if (ops.includes(value)) {
                    return Promise.reject(value + ' is already used');
                }
                return Promise.resolve();
            },
        },
    ];

    const getNewForm = () => {
        const op = authTypes.length === 1 ? authTypes[0] : authType;
        const iconSize = (op && oidcSettings[op]) ? oidcSettings[op].icon.size : oidcSettings.icon.size;
        return <>
            <UploadSvgComponent
                size={iconSize}
                onFileChange={(file) => setIcon(file.svgOptimizedContent)}
                defaultIcon={getDefaultIcon(op, isDark)}
            />
            <br />
            <ProFormText
                name='name'
                hidden={op !== 'custom'}
                label={plain('Name', '')}
                initialValue={undefined}
                rules={nameRules}
            />
            <ProFormText
                name='clientId'
                label={plain('Client id', '')}
                rules={[{ required: true }]}
            />
            <ProFormText.Password
                fieldProps={{ autoComplete: 'off' }}
                rules={[
                    {
                        whitespace: true,
                        required: true,
                    },
                ]}
                name='clientSecret'
                label={plain('Client Secret')}
            />
            {!shouldShowField(op, 'force_metadata_timeout') ? null : <ProFormDigit
                fieldProps={{ autoComplete: 'off' }}
                rules={forceMetadataTimeoutRules}
                name='forceMetadataTimeout'
                placeholder={plain('0 means no timeout, empty means default (3600)')}
                label={plain('Timeout(seconds) to force a refresh of metadata(e.g. JWKS) from OIDC providers')}
            />}
            {!shouldShowField(op, 'issuer') ? null : <ProFormText
                fieldProps={{ autoComplete: 'off' }}
                rules={pemfileRules}
                name='pemfile'
                placeholder={plain('The file must exists if is set')}
                label={plain('Custom Certificate PEM File Path (on the server)')}
            />}
            {!shouldShowField(op, 'issuer') ? null : <ProFormText
                fieldProps={{ autoComplete: 'off' }}
                rules={[
                    {
                        whitespace: true,
                    },
                ]}
                name='issuer'
                label={plain('Issuer', '')}
            />}
            {getNewCustomItems(op)}
        </>;
    }

    const formValuesToProvider = (values: Record<string, any>) => {
        const extraScopes = values.extra_scopes?.map((x: { scope: any; }) => x.scope.trim()).filter((x: string) => x !== '');
        const extraParams = values.extra_params?.reduce((acc: Record<string, any>, { key, value }: any) => {
            if (key) {
                const k = key.trim();
                if (k !== '') {
                    acc[k] = value;
                }
            }
            return acc;
        }, {} as Record<string, string>);
        return {
            name: values.name,
            icon: icon,
            client_id: values.clientId,
            client_secret: values.clientSecret,
            force_metadata_timeout: values.forceMetadataTimeout,
            pemfile: values.pemfile,
            issuer: values.issuer,
            enabled: values.enabled ?? true,
            authorization_endpoint: values.authorizationEndpoint,
            token_endpoint: values.tokenEndpoint,
            userinfo_endpoint: values.userinfoEndpoint,
            jwks_endpoint: values.jwksEndpoint,
            pkce: values.pkce,
            map_groups: values.mapGroups,
            extra_scopes: extraScopes,
            extra_params: extraParams,
        };
    }

    const handleSubmit = async (values: Record<string, any>) => {
        try {
            await form.validateFields();
        } catch (e) {
            return;
        }

        const oidcProviders: API.OidcProviders = {
            callback_url: getCallbackUrl(),
            use_avatar: getUseAvatar() ?? true,
            providers: [formValuesToProvider(values)],
        };
        try {
            await updateOidcProviders(oidcProviders);
            message.success("Add provider successfully.");
            onAdded(values.name);
            handleModalVisible(false);
        } catch (e) {
            message.error("Failed to add provider: " + e);
        }
    }

    if (!visible) return null;
    if (authTypes.length === 0) return null;
    return (
        <ModalForm
            title={plain('New Auth Provider', '')}
            visible={visible}
            width='400px'
            onVisibleChange={handleModalVisible}
            onFinish={handleSubmit}
            form={form}
        >
            {authTypes.length > 1 ? <ProFormSelect
                options={authTypes}
                name='authType'
                label={plain('Auth Type', '')}
                onChange={(e) => {
                    let name = e;
                    setAuthType(name as any);
                    if (name === 'custom') {
                        name = '';
                    }
                    form.setFieldsValue({
                        name: name,
                    });
                }}
            /> : null}
            {authTypes.length === 1 || authType ? getNewForm() : null}
        </ModalForm>
    );
};

export default NewForm;
