import React, { useRef, useState } from 'react';
import { Card, Typography, message, Button, Tooltip, Modal, Flex, theme, Tabs, Breadcrumb } from 'antd';
import { useIntl, useModel } from 'umi';
import type { ProFormInstance } from '@ant-design/pro-form';
import ProForm, { ProFormCheckbox, ProFormDigit, ProFormSwitch, ProFormText } from '@ant-design/pro-form';
import { getOidcProviders, updateOidcProviders, deleteOidcProvider, reorderOidcProviders, checkRead } from '@/services/api';
import Icon, { PlusOutlined, DeleteOutlined, QuestionCircleOutlined } from '@ant-design/icons';
import { extractApiErrorMessage, getOidcSettings, svgSentimentVeryDissatisfied, t } from '@/global';
import type { API } from '@/services/typings';
import { PageContainer } from '@ant-design/pro-layout';
import NewForm, { ExtraScopesFormList, ExtraParamsFormList } from './components/NewForm';
import DraggableTabs from '@/components/Others/draggable_tab';
import UploadSvgComponent from '@/components/Others/upload_svg';
import styles from "./styles.css";
import type { Rule } from 'antd/lib/form';
import { useAntdConfig } from '@umijs/max';
import { checkHasAlgorithm } from '@/components/RightContent/ThemeSwitch';
const { darkAlgorithm } = theme;

const { TabPane } = Tabs;

type FormScope = {
    scope: string;
}

type FormParam = {
    key: string;
    value: string;
}

type FormProvider = {
    name?: string;
    client_id?: string;
    client_secret?: string;
    issuer?: string,
    enabled?: boolean,
    authorization_endpoint?: string,
    token_endpoint?: string,
    userinfo_endpoint?: string,
    jwks_endpoint?: string,
    pkce?: boolean,
    map_groups?: boolean,
    extra_scopes?: FormScope[],
    extra_params?: FormParam[],
}

type FormOidcProvider = {
    callback_url?: string;
    use_avatar?: boolean;
    providers: Record<string, FormProvider>;
}

const guessCallbackUrl = () => {
    return window.location.origin;
};

export const getDefaultIcon = (op: string | undefined, dark: boolean) => {
    const oidcSettings = getOidcSettings(dark) as any;
    const svgContent = op && oidcSettings[op] ? oidcSettings[op].icon.content : oidcSettings.icon.content;
    const iconSize = op && oidcSettings[op] ? oidcSettings[op].icon.size : oidcSettings.icon.size;
    const style = { width: iconSize, height: iconSize };
    return <div
        style={style}
        dangerouslySetInnerHTML={{ __html: svgContent }}
    />;
}

export const shouldShowField = (op: string | undefined, field: string) => {
    const oidcSettings = getOidcSettings(undefined) as any;
    return !op || !oidcSettings[op.toLowerCase()] || oidcSettings[op.toLowerCase()].fields.includes(field);
};

export const pemfileRules = [
    {
        validator: async (_: any, value: string) => {
            if (value === '') {
                return Promise.resolve();
            }

            try {
                await checkRead({ file: value });
            } catch (e) {
                return Promise.reject(e);
            }
            return Promise.resolve();
        },
    },
];

export const forceMetadataTimeoutRules = [
    {
        validator: async (_: any, value?: number) => {
            if (!value) {
                return Promise.resolve();
            }
            if (value < 60) {
                return Promise.reject('The value should be 0 or >= 60.');
            }
            return Promise.resolve();
        },
    },
];

const App: React.FC = () => {
    const { initialState } = useModel('@@initialState');
    const { loading } = initialState!;
    const formRef = useRef<ProFormInstance<FormOidcProvider>>();
    const [opEnabled, setOpEnabled] = useState<boolean>(true);
    const [isFieldsChanged, setIsFieldsChanged] = useState<boolean>(false);
    const intl = useIntl();
    const [op, setOp] = useState<string | undefined>(undefined);
    const [ops, setOps] = useState<string[]>([]);
    const [newModalVisible, handleNewModalVisible] = useState<boolean>(false);
    const [delConfirmModalVisible, handleDelConfirmModalVisible] = useState<boolean>(false);
    const [icon, setIcon] = useState<string | undefined>(undefined);
    const [tabGroupKey, setTabGroupKey] = useState<string>('');
    const [updatingUseAvatar, setUpdatingUseAvatar] = useState<boolean>(false);
    const antdConfig = useAntdConfig();
    const isDark = checkHasAlgorithm(antdConfig, darkAlgorithm);
    const oidcSettings = getOidcSettings(isDark) as any;

    const plain = (text: string, defaultMessage = '') => t(`pages.Settings.OIDC.${text}`, true, defaultMessage || text, intl) as string;
    const showUpdateError = (text: string, e: unknown) => {
        const details = extractApiErrorMessage(e);
        const prefix = text;
        message.error(details ? `${prefix}: ${details}` : prefix);
    };

    function removeCallbackFromUrl(url: string): string {
        const suffix = '/api/oidc/callback';
        if (url.endsWith(suffix)) {
            return url.substring(0, url.length - suffix.length);
        } else {
            return url;
        }
    }

    function addCallbackToUrl(url: string): string {
        const suffix = '/api/oidc/callback';

        if (url.trim() !== '' && !url.endsWith(suffix)) {
            return url + suffix;
        } else {
            return url;
        }
    }

    const fetchOidcProviders = async (setState: boolean) => {
        const oidcProviders = await getOidcProviders();
        const url = addCallbackToUrl(guessCallbackUrl());
        if (oidcProviders.callback_url && oidcProviders.callback_url !== url) {
            oidcProviders.callback_url = url;
            try {
                updateOidcProviders(oidcProviders); // no wait
            } catch (e) { }
        }
        const opsTmp = oidcProviders.providers?.map((provider) => provider.name ?? '') || [];
        setOps(opsTmp);
        setTabGroupKey('providers:' + opsTmp.join(','));
        if (setState) {
            if (opsTmp.length > 0) {
                setOp(opsTmp[0]);
                const provider = oidcProviders.providers?.find((p) => p.name === opsTmp[0]);
                setOpEnabled(provider?.enabled ?? false);
                setIcon(provider?.icon);
            } else {
                setOp(undefined);
                setIcon(undefined);
            }
        }
        return oidcProviders;
    }

    const fetchFormOidcProviders = async (setState: boolean) => {
        const oidcProviders = await fetchOidcProviders(setState);
        const formOidcProvider: FormOidcProvider = {
            callback_url: removeCallbackFromUrl(addCallbackToUrl(guessCallbackUrl())),
            use_avatar: oidcProviders.use_avatar ?? true,
            providers: {},
        };

        oidcProviders.providers?.forEach((provider) => {
            const extra_scopes = (provider.extra_scopes || []).map((scope: string) => ({ scope }));
            const extra_params = Object.entries(provider.extra_params || {}).map(([key, value]) => ({ key, value }));

            formOidcProvider.providers[provider.name || ''] = {
                ...provider,
                extra_params,
                extra_scopes,
            };
        });

        return formOidcProvider;
    };

    const onAdded = async (n: string) => {
        formRef.current?.setFieldsValue(await fetchFormOidcProviders(true));
        setOp(n);
    }

    const formRequest = async () => {
        return await fetchFormOidcProviders(true);
    }

    const getCallbackUrl = () => {
        return addCallbackToUrl(guessCallbackUrl());
    }

    const handleUseAvatarChange = async (checked: boolean) => {
        setUpdatingUseAvatar(true);
        try {
            await updateOidcProviders({
                callback_url: getCallbackUrl(),
                use_avatar: checked,
                providers: [],
            });
        } catch (e) {
            formRef.current?.setFieldsValue({
                use_avatar: !checked,
            });
            showUpdateError("Failed to update OIDC setting", e);
        } finally {
            setUpdatingUseAvatar(false);
        }
    };

    const handleSubmit = async (formOidcProvider: FormOidcProvider) => {
        const providers = Object.entries(formOidcProvider.providers).filter(([name]) => name == op).map(([name, provider]) => {
            const { extra_scopes, extra_params, ...rest } = provider;
            const p: API.OidcProvider = {
                name,
                ...rest,
                extra_scopes: extra_scopes?.map((x: { scope: any; }) => x.scope.trim()).filter((x: string) => x !== ''),
                extra_params: extra_params?.reduce((acc: Record<string, string>, { key, value }: any) => {
                    let k = key;
                    if (k) {
                        k = k.trim();
                        if (k !== '') {
                            acc[k as string] = value;
                        }
                    }
                    return acc;
                }, {} as Record<string, string>),
            };
            if (p.icon != icon) {
                p.icon = icon;
            }
            return p;
        });

        if (providers.length != 1) {
            message.error("The provider entry should never be empty!");
            return;
        }

        // formOidcProvider to oidcProviders
        const oidcProviders: API.OidcProviders = {
            callback_url: getCallbackUrl(),
            use_avatar: formOidcProvider.use_avatar ?? true,
            providers: providers,
        };
        try {
            await updateOidcProviders(oidcProviders);
            formRef.current?.setFieldsValue(await fetchFormOidcProviders(false));
            message.success("Update provider successfully.");
        } catch (e) {
            showUpdateError("Failed to update provider", e);
        }
    };

    const addOidcButton = () => {
        return <Button type="primary" onClick={() => { handleNewModalVisible(true); }} style={{ marginBottom: '18px' }} >
            <PlusOutlined />
            {plain('New Auth Provider')}
        </Button>
    }

    const getCommonInput = () => {
        return <Card style={{ marginBottom: 36 }}>
            <ProForm.Item label={t('Callback URL', true)}>
                <Typography.Text copyable code={true} style={{ fontSize: 17 }}>
                    {addCallbackToUrl(guessCallbackUrl())}
                </Typography.Text>
            </ProForm.Item>
            <ProForm.Item style={{ marginBottom: 0 }}>
                <Flex align='center' gap={15}>
                    <Flex align='center' gap={6}>
                        <span>{plain('Use Avatar', 'Use Avatar')}</span>
                        <Tooltip
                            title={plain(
                                'use_avatar_tip',
                                'Sync the avatar when creating a new user.',
                            )}
                        >
                            <QuestionCircleOutlined style={{ color: 'gray', cursor: 'help' }} />
                        </Tooltip>
                    </Flex>
                    <ProFormSwitch
                        name='use_avatar'
                        noStyle
                        fieldProps={{
                            disabled: updatingUseAvatar,
                            onChange: handleUseAvatarChange,
                        }}
                    />
                </Flex>
            </ProForm.Item>
        </Card>
    }

    const handleDelete = async () => {
        try {
            await deleteOidcProvider(op || '');
            message.success("Delete provider successfully.");
            await fetchOidcProviders(true);
            handleDelConfirmModalVisible(false);
        } catch (e) {
            showUpdateError("Failed to delete provider", e);
        }
    };

    const handleReorder = async (items: string[]) => {
        try {
            await reorderOidcProviders(items);
            setOps(items);
        } catch (e) {
            showUpdateError("Failed to reorder provider", e);
        }
    }

    const getProviderInput = (providerName: string) => {
        const getCommonItem = (field: string, label: string, required: boolean, placeholder?: string, rules?: Rule[]) => {
            return <ProFormText
                fieldProps={{ autoComplete: 'off', disabled: !opEnabled }}
                rules={rules ?? [
                    {
                        whitespace: true,
                        required: required,
                    },
                ]}
                labelCol={{ span: 10, offset: 0 }} labelAlign={'left'}
                width='md'
                name={['providers', providerName, field]}
                placeholder={placeholder}
                label={plain(label)}
            />;
        };

        const getSecretItem = (field: string, label: string) => {
            return <ProFormText.Password
                fieldProps={{ autoComplete: 'off', disabled: !opEnabled }}
                rules={[
                    {
                        whitespace: true,
                        required: true,
                    },
                ]}
                labelAlign={'left'}
                width='md'
                name={['providers', providerName, field]}
                label={plain(label)}
            />;
        };

        return <Card
            title={
                <Flex justify="start" align='center'>
                    <Tooltip title={plain('Click to Change Icon')}>
                        <UploadSvgComponent
                            disabled={!opEnabled}
                            size={oidcSettings[providerName]?.icon.size ?? oidcSettings.icon.size}
                            svgContent={icon}
                            onFileChange={(file) => {
                                setIcon(file.svgOptimizedContent);
                                setIsFieldsChanged(true);
                            }}
                            defaultIcon={getDefaultIcon(providerName, isDark)}
                        />
                    </Tooltip>
                    <div style={{ width: 20 }} />
                    <ProFormSwitch name={['providers', providerName, "enabled"]} noStyle />
                    <Tooltip title={plain('Delete This Provider')}>
                        <DeleteOutlined
                            onClick={() => { handleDelConfirmModalVisible(true); }}
                            style={{ position: 'absolute', right: 24, color: 'red' }}
                        />
                    </Tooltip>
                </Flex >
            }
            style={{ marginBottom: 36 }}
        >
            <ProForm.Group>
                {getCommonItem('client_id', 'Client ID', true)}
                {getSecretItem('client_secret', 'Client Secret')}
            </ProForm.Group  >
            {
                shouldShowField(providerName, 'force_metadata_timeout') ? <ProFormDigit
                    fieldProps={{ autoComplete: 'off', disabled: !opEnabled }}
                    labelCol={{ span: 10, offset: 0 }} labelAlign={'left'}
                    rules={forceMetadataTimeoutRules}
                    width='md'
                    name={['providers', providerName, 'force_metadata_timeout']}
                    placeholder={plain('0 means no timeout, empty means default (3600)')}
                    label={plain('Timeout(seconds) to force a refresh of metadata(e.g. JWKS) from OIDC providers')}
                /> : null
            }
            {
                shouldShowField(providerName, 'pemfile') ? getCommonItem(
                    'pemfile',
                    'Custom Certificate PEM File Path (on the server)',
                    false,
                    'The file must exists if is set',
                    pemfileRules) : null
            }
            {
                shouldShowField(providerName, 'issuer') ? getCommonItem('issuer', 'Issuer', false) : null
            }
            {
                shouldShowField(providerName, 'authorization_endpoint') ? getCommonItem('authorization_endpoint', 'Authorization Endpoint', false) : null
            }
            {
                shouldShowField(providerName, 'token_endpoint') ? getCommonItem('token_endpoint', 'Token Endpoint', false) : null
            }
            {
                shouldShowField(providerName, 'userinfo_endpoint') ? getCommonItem('userinfo_endpoint', 'Userinfo Endpoint', false) : null
            }
            {
                shouldShowField(providerName, 'jwks_endpoint') ? getCommonItem('jwks_endpoint', 'JWKS Endpoint', false) : null
            }
            {
                shouldShowField(providerName, 'pkce') ? <ProFormCheckbox
                    fieldProps={{ disabled: !opEnabled }}
                    labelCol={{ span: 10, offset: 0 }} labelAlign={'left'}
                    width='md'
                    name={['providers', providerName, 'pkce']}
                >{plain('Enable PKCE')}</ProFormCheckbox> : null
            }
            {
                shouldShowField(providerName, 'map_groups') ? <ProFormCheckbox
                    fieldProps={{ disabled: !opEnabled }}
                    labelCol={{ span: 10, offset: 0 }} labelAlign={'left'}
                    width='md'
                    name={['providers', providerName, 'map_groups']}
                ><Tooltip title={plain('oidc_map_groups_tooltip')}><span>{plain('Map Groups')}</span></Tooltip></ProFormCheckbox> : null
            }
            {
                shouldShowField(providerName, 'extra_scopes') ? ExtraScopesFormList(plain('Add Extra Scope', ''), () => !opEnabled, providerName) : null
            }
            {
                shouldShowField(providerName, 'extra_params') ? ExtraParamsFormList(plain('Add Extra Param', ''), () => !opEnabled, providerName) : null
            }
        </Card>
    }

    const getProviderTabs = () => {
        return <DraggableTabs
            key={tabGroupKey}
            onDrop={handleReorder}
            tabAction={addOidcButton()}
            onChange={(activeKey: string) => {
                setOp(activeKey);
                setIcon(formRef.current?.getFieldValue(["providers", activeKey, "icon"]));
                setIsFieldsChanged(false);
                setOpEnabled(formRef.current?.getFieldValue(["providers", activeKey, "enabled"]));
            }}
            defaultActiveKey={op}
        >
            {
                ops.map((i) => {
                    return (
                        <TabPane tab={i} key={i}>
                            <div>
                                {getProviderInput(i)}
                            </div>
                        </TabPane>
                    )
                })
            }
        </DraggableTabs>;
    };

    return (
        <div className={styles['page-container']}>
            <PageContainer
                breadcrumbRender={() => (
                    <Breadcrumb items={[
                        { title: t('menu.Settings', true) },
                        { title: t('OIDC', true) },
                    ]} />
                )}
            >
                {loading ? null : (
                    <div>
                        <ProForm
                            formRef={formRef}
                            onValuesChange={(changedValues, allValues) => {
                                const changedKeys = Object.keys(changedValues || {});
                                const changedUseAvatarOnly = changedKeys.length === 1 && changedKeys[0] === 'use_avatar';
                                if (!changedUseAvatarOnly) {
                                    setIsFieldsChanged(true);
                                }
                                if (op) {
                                    const ps = allValues.providers;
                                    if (ps && ps[op]) {
                                        const p = ps[op];
                                        setOpEnabled(p?.enabled ?? false);
                                    }
                                }
                            }}
                            onReset={() => {
                                if (op) {
                                    setOpEnabled(formRef.current?.getFieldValue(["providers", op, "enabled"]));
                                    setIcon(formRef.current?.getFieldValue(["providers", op, "icon"]));
                                    setIsFieldsChanged(false);
                                }
                            }}
                            onFinish={handleSubmit}
                            request={formRequest}
                            requiredMark
                            submitter={{
                                resetButtonProps: {
                                    style: {
                                        display: op ? undefined : 'none',
                                    },
                                    disabled: !isFieldsChanged,
                                },
                                submitButtonProps: {
                                    style: {
                                        display: op ? undefined : 'none',
                                    },
                                    disabled: !isFieldsChanged,
                                },
                            }}
                        >
                            {op && getCommonInput()}
                            {getProviderTabs()}
                        </ProForm>
                    </div>
                )}
                {newModalVisible && <NewForm
                    getCallbackUrl={getCallbackUrl}
                    getUseAvatar={() => formRef.current?.getFieldValue(['use_avatar'])}
                    visible={newModalVisible}
                    handleModalVisible={handleNewModalVisible}
                    ops={ops}
                    onAdded={onAdded}
                />}
                {delConfirmModalVisible && <Modal
                    title={<span>{plain('confirm-delete-title')}&nbsp;&nbsp;<b style={{ fontSize: 20 }}>{op || ''}</b></span>}
                    open={delConfirmModalVisible}
                    onOk={handleDelete}
                    onCancel={() => { handleDelConfirmModalVisible(false); }}
                ><div>{plain('confirm-delete-content')}</div></Modal>
                }
            </PageContainer >
            {!op && <div className={styles['empty-prompt-container']}>
                <div className={styles['empty-prompt-content']}>
                    <div className={styles['empty-prompt-container']}>
                        <Icon className={styles['empty-prompt-content']} component={() => svgSentimentVeryDissatisfied()} />
                    </div>
                    <div>{plain('emptyPrompt')}</div>
                </div>
            </div>}
        </div>
    );
};

export default App;
