import React, { useCallback, useRef } from 'react';
import DropzoneAreaBase from 'react-dropzone';
// import { optimize } from 'svgo';

type UploadedFile = {
    name: string;
    size: number;
    svgContent: string;
    svgOptimizedContent?: string;
}

type Props = {
    disabled?: boolean;
    size: number;
    svgContent?: string;
    onFileChange: (file: UploadedFile) => void;
    defaultIcon?: React.ReactNode;
}

const UploadSvgComponent: React.FC<Props> = ({ disabled, size, svgContent, onFileChange, defaultIcon }) => {
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleDrop = useCallback(async (acceptedFiles: any) => {
        const file = acceptedFiles[0];
        if (!fileInputRef.current) return;
        fileInputRef.current.value = '';
        const reader = new FileReader();
        reader.readAsText(file);
        reader.onload = () => {
            const content = reader.result as string;
            const svgOptimizedContent = content;
            onFileChange({ name: file.name, size: file.size, svgContent: content, svgOptimizedContent });
        };
    }, [onFileChange]);

    const getPicComponent = () => {
        const style = {
            width: size,
            height: size,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
        };
        return svgContent ? <div
            style={style}
            dangerouslySetInnerHTML={{ __html: svgContent }}
        /> :
            (defaultIcon ? defaultIcon : <div>SVG HERE</div>);
    }

    return (
        <DropzoneAreaBase
            disabled={disabled}
            onDrop={handleDrop}
            accept={{ image: ['svg+xml'] }}
            multiple={false}
            maxFiles={1}
        >
            {() => {
                return <>
                    <label htmlFor='file-input' style={{ cursor: disabled ? 'default' : 'pointer' }}>
                        {getPicComponent()}
                    </label>
                    <input
                        disabled={disabled}
                        id='file-input'
                        type='file'
                        style={{ display: 'none' }}
                        onChange={(e) => handleDrop(e.target.files)}
                        accept='.svg'
                        ref={fileInputRef}
                    />
                </>;
            }}
        </DropzoneAreaBase>
    );
};

export default UploadSvgComponent;
