import React from 'react';
import { Space, Tabs, Tooltip } from 'antd';
import { useIntl } from 'umi';
import { DndProvider, useDrag, useDrop } from "react-dnd";
import { HTML5Backend } from 'react-dnd-html5-backend';
import { QuestionCircleOutlined } from '@ant-design/icons';
import { t } from '@/global';
import styles from './draggable_tab.less';

type DraggableTabNodeProps = {
    index: string;
    children: React.ReactNode;
    moveNode: (dragIndex: string, hoverIndex: string) => void;
}

const type = 'DraggableTabNode';

const DraggableTabNode: React.FC<DraggableTabNodeProps> = ({ index, children, moveNode }) => {
    const [{ isDragging }, drag] = useDrag({
        type,
        item: { index },
        collect: (monitor) => ({
            isDragging: monitor.isDragging(),
        }),
    });

    const [{ }, drop] = useDrop({
        accept: type,
        drop: (item: { index: string }) => {
            moveNode(item.index, index);
        },
        collect: (monitor) => {
            const { index: dragIndex } = monitor.getItem() || {};
            if (dragIndex === index) {
                return {};
            }
            return {
                canDrop: monitor.canDrop(),
                isOver: monitor.isOver(),
                dropClassName: 'dropping',
            };
        },
    });

    return (
        <div key={index} ref={drop} className={styles.dragnode}>
            <div
                ref={drag}
                className={ isDragging ? styles.dragging : null}
            >
                {children}
            </div>
        </div>
    );
};

const DraggableTabTooptip: React.FC = () => {
    const intl = useIntl();
    const plain = (text: string, defaultMessage = '') => t(`DraggableTab.${text}`, true, defaultMessage || text, intl) as string;

    return (
        <Tooltip title={plain('Drag tab to reorder')} placement='top'>
            <QuestionCircleOutlined style={{ color: 'gray', cursor: 'help' }} />
        </Tooltip>
    );
}

interface DraggableTabsProps {
    children: React.ReactNode;
    header?: React.ReactNode;
    tabAction?: React.ReactNode;
    onDrop: (items: string[]) => void;
    onChange?: (activeKey: string) => void;
    defaultActiveKey?: string;
}

interface DraggableTabsState {
    order: string[];
}

class DraggableTabs extends React.Component<DraggableTabsProps, DraggableTabsState> {
    state: DraggableTabsState = {
        order: [],
    };

    moveTabNode = (dragKey: string, hoverKey: string) => {
        const newOrder = this.state.order.slice();
        const { children, onDrop } = this.props;

        React.Children.forEach(children, (c) => {
            if (newOrder.indexOf((c as React.ReactElement).key as string) === -1) {
                newOrder.push((c as React.ReactElement).key as string);
            }
        });

        const dragIndex = newOrder.indexOf(dragKey);
        const hoverIndex = newOrder.indexOf(hoverKey);

        newOrder.splice(dragIndex, 1);
        newOrder.splice(hoverIndex, 0, dragKey);

        // Ignore the failure of updating the order on server, because the order is not very important.
        onDrop(newOrder);
        this.setState({
            order: newOrder,
        });
    };

    renderTabBar = (props: any, DefaultTabBar: any) => {
        const { tabAction } = this.props;
        return (
            <>
                <div style={{ display: 'flex', alignItems: 'center' }}>
                    <DefaultTabBar {...props}>
                        {(node: any) => (
                            <DraggableTabNode key={node.key} index={node.key} moveNode={this.moveTabNode}>
                                {node}
                            </DraggableTabNode>
                        )}
                    </DefaultTabBar>
                    <span style={{ marginBottom: '18px' }}>
                        <DraggableTabTooptip />
                    </span>
                    <span style={{ marginLeft: '32px' }}>
                        {tabAction}
                    </span>
                </div>
            </>
        );
    };

    render() {
        const { order } = this.state;
        const { header, children, onChange, defaultActiveKey } = this.props;

        const tabs: React.ReactElement[] = [];
        React.Children.forEach(children, (c) => {
            tabs.push(c as React.ReactElement);
        });

        const orderTabs = tabs.slice().sort((a, b) => {
            const orderA = order.indexOf(a.key as string);
            const orderB = order.indexOf(b.key as string);

            if (orderA !== -1 && orderB !== -1) {
                return orderA - orderB;
            }
            if (orderA !== -1) {
                return -1;
            }
            if (orderB !== -1) {
                return 1;
            }

            const ia = tabs.indexOf(a);
            const ib = tabs.indexOf(b);

            return ia - ib;
        });

        const otherProps = { children: this.props.children };

        return (
            <div>
                <Space>
                    {header}
                </Space>
                <DndProvider backend={HTML5Backend}>
                    <Tabs
                        onChange={onChange}
                        renderTabBar={this.renderTabBar}
                        defaultActiveKey={defaultActiveKey}
                        size='large'
                        {...otherProps}
                    >
                        {orderTabs}
                    </Tabs>
                </DndProvider>
            </div>
        );
    }
}

export default DraggableTabs;
